#include<bits/stdc++.h>
using namespace std;
int n1,n2,ans;
string s1,s2,str1,str2;
int main()
{
    while(cin>>s2>>n2>>s1>>n1)
    {
        str1=str2="";
        ans=0;
        for(int i=0;i<n1;i++)
        {
            str1+=s1;
        }
        str2=s2;
        int n=str1.length(),m=str2.length();
        for(int i=0,j=0;i<n;i++)
        {
            if(str1[i]==str2[j])
            {
                if(j+1==m)
                {
                    ans++;
                    j=0;
                }
                else
                {
                    j++;
                }
            }
        }
        printf("%d\n",ans/n2);
    }
    return 0;
}
